// ===================================================
// WF-08 Step 1: 관리자 토큰 검증 + 입력값 파싱
// Authorization: Bearer {ADMIN_API_TOKEN} 헤더 필수
// 필수: application_id 또는 member_id
// 선택: reviewer_note
// ===================================================

const input = $input.first().json;
const body = input.body || input;
const headers = input.headers || {};

// === 관리자 토큰 검증 ===
// Authorization 헤더에서 Bearer 토큰 추출
const authHeader = headers.authorization || headers.Authorization || '';
const adminToken = $env.ADMIN_API_TOKEN || '';

if (!authHeader || !authHeader.startsWith('Bearer ')) {
  return [{
    json: {
      _valid: false,
      _errorCode: 401,
      _errorResponse: {
        success: false,
        error: {
          code: 'UNAUTHORIZED',
          message: '관리자 인증이 필요합니다. Authorization: Bearer {token} 헤더를 포함해 주세요.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const providedToken = authHeader.substring(7).trim();
if (!adminToken || providedToken !== adminToken) {
  return [{
    json: {
      _valid: false,
      _errorCode: 403,
      _errorResponse: {
        success: false,
        error: {
          code: 'FORBIDDEN',
          message: '관리자 토큰이 유효하지 않습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 텍스트 정제 ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === 필수 파라미터 검증 ===
const applicationId = sanitizeText(body.application_id, 100);
const memberId = sanitizeText(body.member_id, 100);
const reviewerNote = sanitizeText(body.reviewer_note, 500);

if (!applicationId && !memberId) {
  return [{
    json: {
      _valid: false,
      _errorCode: 400,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: 'application_id 또는 member_id가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _valid: true,
    applicationId,
    memberId,
    reviewerNote
  }
}];

// ===================================================
// WF-08 Step 2: 신청 조회 결과 확인 + PENDING 상태 검증
// ===================================================

const response = $input.first().json;
const appList = response.list || [];
const validData = $('Validate Auth & Input').first().json;

if (appList.length === 0) {
  return [{
    json: {
      _found: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'APPLICATION_NOT_FOUND',
          message: '해당 파트너 신청을 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const app = appList[0];

// 이미 승인된 신청
if (app.status === 'APPROVED') {
  return [{
    json: {
      _found: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'ALREADY_APPROVED',
          message: '이미 승인된 신청입니다.'
        },
        data: {
          application_id: app.application_id || ''
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// REJECTED 등 다른 상태
if (app.status !== 'PENDING') {
  return [{
    json: {
      _found: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_STATUS',
          message: '현재 상태(' + app.status + ')에서는 승인할 수 없습니다. PENDING 상태만 승인 가능합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _found: true,
    _application: {
      Id: app.Id || app.id,
      application_id: app.application_id || '',
      member_id: app.member_id || '',
      applicant_name: app.applicant_name || '',
      workshop_name: app.workshop_name || '',
      email: app.email || '',
      phone: app.phone || '',
      location: app.location || '',
      specialty: app.specialty || '',
      portfolio_url: app.portfolio_url || '',
      instagram_url: app.instagram_url || '',
      introduction: app.introduction || ''
    },
    reviewerNote: validData.reviewerNote
  }
}];

// ===================================================
// WF-08 Step 3: 기존 파트너 중복 확인 + partner_code 생성
// partner_code 형식: PC_YYYYMM_NNN (NNN = 해당 월 순번)
// ===================================================

const partnerResponse = $input.first().json;
const partnerList = partnerResponse.list || [];
const prevData = $('Check Application Status').first().json;

// 이미 파트너로 등록된 경우
if (partnerList.length > 0) {
  const existing = partnerList[0];
  return [{
    json: {
      _canApprove: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'ALREADY_PARTNER',
          message: '이 회원은 이미 파트너로 등록되어 있습니다.'
        },
        data: {
          partner_code: existing.partner_code || '',
          member_id: existing.member_id || ''
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _canApprove: true,
    _application: prevData._application,
    reviewerNote: prevData.reviewerNote
  }
}];

// ===================================================
// WF-08 Step 4: partner_code 생성 (PC_YYYYMM_NNN)
// NNN = 해당 월 기존 파트너 수의 최대 순번 + 1
// ===================================================

const monthPartnersResponse = $input.first().json;
const monthPartners = monthPartnersResponse.list || [];
const prevData = $('Check Partner Duplicate').first().json;

const now = new Date();
const pad2 = (n) => String(n).padStart(2, '0');
const currentMonth = String(now.getFullYear()) + pad2(now.getMonth() + 1);
const prefix = 'PC_' + currentMonth + '_';

// 해당 월 파트너 코드에서 최대 순번 추출
let maxNum = 0;
for (const p of monthPartners) {
  const code = String(p.partner_code || '').trim();
  if (code.startsWith(prefix)) {
    const numStr = code.substring(prefix.length);
    const num = parseInt(numStr, 10);
    if (!isNaN(num) && num > maxNum) {
      maxNum = num;
    }
  }
}

const partnerCode = prefix + String(maxNum + 1).padStart(3, '0');
const approvedDate = now.toISOString();

// === 한국 날짜 포맷 (이메일용) ===
const approvedDateKR = now.getFullYear() + '년 '
  + (now.getMonth() + 1) + '월 '
  + now.getDate() + '일';

// === 수수료 설정 (SILVER 기본) ===
const COMMISSION_RATES = {
  SILVER:   { commissionRate: 0.10, reserveRate: 1.00 },
  GOLD:     { commissionRate: 0.12, reserveRate: 1.00 },
  PLATINUM: { commissionRate: 0.15, reserveRate: 0.80 }
};
const grade = 'SILVER';
const rateConfig = COMMISSION_RATES[grade];

return [{
  json: {
    _partnerCode: partnerCode,
    _grade: grade,
    _commissionRate: rateConfig.commissionRate,
    _reserveRate: rateConfig.reserveRate,
    _approvedDate: approvedDate,
    _approvedDateKR: approvedDateKR,
    _application: prevData._application,
    reviewerNote: prevData.reviewerNote
  }
}];

// ===================================================
// WF-08 Step 5: Application 업데이트 결과 확인 + Partner 생성 데이터 준비
// ===================================================

const updateResult = $input.first().json;
const prevData = $('Generate Partner Code').first().json;

// 업데이트 성공 여부 (NocoDB PATCH는 업데이트된 레코드 반환)
const app = prevData._application;

// 파트너명: 공방명 우선, 없으면 본명
const partnerName = app.workshop_name || app.applicant_name;

return [{
  json: {
    ...prevData,
    _partnerName: partnerName
  }
}];

// ===================================================
// WF-08 Step 6: 파트너 생성 결과 확인
// ===================================================

const createResult = $input.first().json;
const prevData = $('Prepare Partner Data').first().json;

const recordCreated = !!createResult.Id || !!createResult.id;

if (!recordCreated) {
  return [{
    json: {
      _partnerCreated: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'PARTNER_CREATE_FAILED',
          message: '파트너 레코드 생성에 실패했습니다.'
        },
        timestamp: new Date().toISOString()
      },
      _telegramError: '파트너 레코드 생성 실패: '
        + prevData._partnerName + ' (' + prevData._application.member_id + ')'
    }
  }];
}

return [{
  json: {
    _partnerCreated: true,
    ...prevData,
    _partnerRecordId: createResult.Id || createResult.id
  }
}];

// ===================================================
// WF-08 Step 7a: 메이크샵 회원등급 변경 결과 확인
// 실패해도 파트너 등록은 유지 (수동으로 변경 가능)
// ===================================================

const makeshopResult = $input.first().json;
const prevData = $('Check Partner Created').first().json;

// 메이크샵 API 응답 확인
let makeshopSuccess = false;
let makeshopMessage = '';

try {
  // 메이크샵 API: return_code === '0000' + result === true
  if (makeshopResult.return_code === '0000'
      || (makeshopResult.datas && makeshopResult.datas[0] && makeshopResult.datas[0].result === true)) {
    makeshopSuccess = true;
    makeshopMessage = '회원등급 변경 성공';
  } else {
    makeshopMessage = '회원등급 변경 실패: ' + JSON.stringify(makeshopResult).substring(0, 200);
  }
} catch (e) {
  makeshopMessage = '회원등급 변경 응답 파싱 실패: ' + e.message;
}

return [{
  json: {
    ...prevData,
    _makeshopSuccess: makeshopSuccess,
    _makeshopMessage: makeshopMessage
  }
}];

// ===================================================
// WF-08 Step 7b: 승인 안내 이메일 HTML 생성
// brand-strategy-comprehensive.md 이메일 5 참고
// 브랜드 톤: 축하 + 기대 + 가이드
// ===================================================

const data = $input.first().json;
const app = data._application;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const partnerName = escapeHtml(data._partnerName);
const partnerCode = escapeHtml(data._partnerCode);
const grade = escapeHtml(data._grade);
const approvedDateKR = escapeHtml(data._approvedDateKR);
const commissionPct = Math.round(data._commissionRate * 100);

const subject = '[PRESSCO21] 파트너 승인이 완료되었습니다! ' + data._partnerName + '님 환영합니다';

const html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>PRESSCO21 파트너 승인 완료</title></head>'
+ '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: \'Pretendard\', \'Apple SD Gothic Neo\', \'Malgun Gothic\', sans-serif;">'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
+ '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">'
// 헤더
+ '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
+ '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
+ '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
+ '</td></tr>'
// APPROVED 배지
+ '<tr><td style="padding: 32px 32px 0; text-align: center;">'
+ '<span style="display: inline-block; background-color: #4a8c5c; color: #ffffff; font-size: 14px; font-weight: 700; padding: 8px 24px; border-radius: 20px; letter-spacing: 1px;">PARTNER APPROVED</span>'
+ '</td></tr>'
// 본문
+ '<tr><td style="padding: 28px 32px 32px;">'
+ '<p style="margin: 0 0 24px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + partnerName + '</strong>님, 환영합니다!</p>'
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">PRESSCO21 블룸 파트너 프로그램에 오신 것을 진심으로 환영합니다.</p>'
+ '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">30년 전통의 압화/보존화 전문 PRESSCO21과 함께<br />아름다운 클래스를 만들어 가요.</p>'
// 파트너 정보 테이블
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
+ '<tr><td style="padding: 20px 24px 12px;"><p style="margin: 0 0 16px; font-size: 14px; font-weight: 700; color: #b89b5e; letter-spacing: 1px;">파트너 정보</p></td></tr>'
+ '<tr><td style="padding: 0 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; width: 100px; vertical-align: top;">파트너 코드</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 700;">' + partnerCode + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">파트너 등급</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">Bloom (블룸) - ' + grade + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">수수료율</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + commissionPct + '%</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">승인일</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + approvedDateKR + '</td></tr>'
+ '</table></td></tr></table>'
// 시작 가이드
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 24px;"><tr><td style="padding: 20px 24px; background-color: #fef9f0; border-radius: 8px; border-left: 3px solid #b89b5e;">'
+ '<p style="margin: 0 0 12px; font-size: 14px; font-weight: 700; color: #b89b5e;">시작 가이드</p>'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0">'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">1.</strong> 필수 교육 이수 (22분 영상 + 퀴즈)<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">부담 없이 편하게 시청해주세요. 70점 이상이면 합격!</span></td></tr>'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">2.</strong> 첫 클래스 등록 요청<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">관리자에게 클래스 정보를 보내주시면 등록해드려요.</span></td></tr>'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">3.</strong> 클래스 오픈 + 첫 수강생 만남!<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">수수료는 수강 완료 후 적립금으로 지급됩니다.</span></td></tr>'
+ '</table></td></tr></table>'
// 등급 안내
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td style="padding: 16px 20px; background-color: #fff8e8; border-radius: 8px; border-left: 4px solid #b89b5e;">'
+ '<p style="margin: 0; font-size: 13px; color: #555555; line-height: 1.6;"><strong>등급 안내:</strong> 수업 실적과 평점에 따라 Garden(가든), Atelier(아틀리에) 파트너로 자동 승급됩니다.<br />Garden: 10건+ / 4.0+ &nbsp;|&nbsp; Atelier: 50건+ / 4.5+</p>'
+ '</td></tr></table>'
// 마무리
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">함께하는 여정이 기대됩니다!</p>'
+ '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">궁금하신 점은 pressco21@foreverlove.co.kr로 연락주세요.</p>'
+ '</td></tr>'
// 서명
+ '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>'
// 푸터
+ '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">문의: pressco21@foreverlove.co.kr</p>'
+ '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 파트너 프로그램 관련 안내 메일입니다.</p>'
+ '</td></tr></table></td></tr></table></body></html>';

return [{
  json: {
    ...data,
    _approvalEmail: {
      to: app.email,
      subject,
      html
    }
  }
}];

// ===================================================
// WF-08 Step 7c: 텔레그램 승인 알림 메시지 구성
// 관리자용 알림 (메이크샵 등급 변경 결과 포함)
// ===================================================

const data = $input.first().json;
const app = data._application;

const makeshopStatus = data._makeshopSuccess
  ? '성공'
  : '실패 (수동 변경 필요): ' + data._makeshopMessage;

const message = '[파트너 승인] 새 파트너가 승인되었습니다\n\n'
  + '신청자: ' + data._partnerName + '\n'
  + '회원ID: ' + app.member_id + '\n'
  + '파트너 코드: ' + data._partnerCode + '\n'
  + '등급: Bloom (' + data._grade + ')\n'
  + '수수료율: ' + Math.round(data._commissionRate * 100) + '%\n'
  + '승인일: ' + data._approvedDateKR + '\n'
  + '\n메이크샵 회원등급 변경: ' + makeshopStatus;

return [{
  json: {
    ...data,
    _telegramMessage: message
  }
}];

// ===================================================
// WF-08 Step 8: 성공 응답 구성
// ===================================================

const data = $('Check Makeshop Result').first().json;

return [{
  json: {
    success: true,
    data: {
      partner_code: data._partnerCode,
      member_id: data._application.member_id,
      partner_name: data._partnerName,
      grade: data._grade,
      commission_rate: data._commissionRate,
      reserve_rate: data._reserveRate,
      approved_date: data._approvedDateKR,
      makeshop_group_changed: data._makeshopSuccess,
      message: '파트너 승인이 완료되었습니다.'
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-08: 파트너 생성 실패 시 에러 텔레그램 알림
// ===================================================

const data = $input.first().json;

const message = '[파트너 승인 실패] 레코드 생성 오류\n\n'
  + (data._telegramError || '알 수 없는 오류');

return [{
  json: {
    ...data,
    _errorTelegramMessage: message
  }
}];
